/// Socket types
pub enum SocketType {
    /// TCP
    STREAM = 1,
    /// UDP
    DGRAM = 2,
    /// Raw IP
    RAW = 3,
    /// RDM
    RDM = 4,
    /// Seq Packet
    SEQPACKET = 5,
    /// DCCP
    DCCP = 6,
    /// Packet
    PACKET = 10,
}

impl TryFrom<i32> for SocketType {
    type Error = SysError;

    fn try_from(value: i32) -> Result<Self, Self::Error> {
        match value {
            1 => Ok(Self::STREAM),
            2 => Ok(Self::DGRAM),
            3 => Ok(Self::RAW),
            4 => Ok(Self::RDM),
            5 => Ok(Self::SEQPACKET),
            6 => Ok(Self::DCCP),
            10 => Ok(Self::PACKET),
            _ => Err(Self::Error::EINVAL),
        }
    }
}

/// Set O_NONBLOCK flag on the open fd
pub const SOCK_NONBLOCK: i32 = 0x800;
/// Set FD_CLOEXEC flag on the new fd
pub const SOCK_CLOEXEC: i32 = 0x80000;

/// specifiy the protocol to be used with the socket
#[derive(Clone, PartialEq, Eq, Debug)]
#[repr(usize)]
#[allow(non_camel_case_types)]
pub enum Protocol{
    IP            = 0,
    /// ICMPv4
    ICMP          = 1,
    /// IGMP
    IGMP          = 2,
    ETH_P_ALL     = 3, 
    /// TCP（SOCK_STREAM 的默认）
    TCP           = 6,
    /// EGP
    EGP           = 8,
    /// PUP
    PUP           = 12,
    /// UDP（SOCK_DGRAM 的默认）
    UDP           = 17,
    /// IDP
    IDP           = 22,
    /// IPv6 路由头
    IPv6         = 41,
    /// ICMPv6
    ICMPv6       = 58,
    IPPROTO_UDPLITE = 136,
    IPPROTO_SCTP = 132,
    ALG_OP_AEAD = 768,
}

impl TryFrom<usize> for Protocol {
    type Error = SysError;

    fn try_from(value: usize) -> Result<Self, Self::Error> {
        match value {
            0 => Ok(Self::IP),
            1 => Ok(Self::ICMP),
            2 => Ok(Self::IGMP),    
            3 => Ok(Self::ETH_P_ALL),
            6 => Ok(Self::TCP),
            8 => Ok(Self::EGP),
            12 => Ok(Self::PUP),
            17 => Ok(Self::UDP),
            22 => Ok(Self::IDP),    
            41 => Ok(Self::IPv6),
            58 => Ok(Self::ICMPv6),
            136 => Ok(Self::IPPROTO_UDPLITE),
            132 => Ok(Self::IPPROTO_SCTP),
            768 => Ok(Self::ALG_OP_AEAD),
            _ => Err(Self::Error::EINVAL),
        }
    }
}

impl Protocol {
    pub fn check_socket_type(self, socket_type: SocketType) -> bool {
        match socket_type {
            SocketType::STREAM | SocketType::SEQPACKET | SocketType::RAW => {
                if self != Protocol::TCP && self != Protocol::IP && self != Protocol::ETH_P_ALL {
                    return false;
                } 
            }
            SocketType::DGRAM => {
                if self != Protocol::UDP && self != Protocol::IP && self != Protocol::IPPROTO_UDPLITE {
                    return false;
                }
            }
            _ => {
                return false;
            }
        }
        true
    }
}
/// create an endpoint for communication and returns a file decriptor refers to the endpoint
/// Since Linux 2.6.27, the type argument serves a second purpose: in
///addition to specifying a socket type, it may include the bitwise
///OR of any of the following values, to modify the behavior of
///socket():
// SOCK_NONBLOCK
//        Set the O_NONBLOCK file status flag on the open file
//        description (see open(2)) referred to by the new file
//        descriptor.  Using this flag saves extra calls to fcntl(2)
//        to achieve the same result.

// SOCK_CLOEXEC
//        Set the close-on-exec (FD_CLOEXEC) flag on the new file
//        descriptor.  See the description of the O_CLOEXEC flag in
//        open(2) for reasons why this may be useful.
pub fn sys_socket(domain: usize, types: i32, protocol: usize) -> SysResult {
    if domain <= 0 || domain > 255 {
        return Err(SysError::EAFNOSUPPORT);
    }
    log::info!("[sys_socket] domain: {:?}, types: {:?}, protocol: {:?}", domain, types, protocol);
    let domain = SaFamily::try_from(domain as u16)?;
    let s_type = SocketType::try_from(types as i32)?;
    // if s_type == SocketType::RAW && domain!= SaFamily::Packet {
    //     return Err(SysError::EPROTONOSUPPORT);
    // }
    let mut types = types as i32;
    let mut nonblock = false;
    // file descriptor flags
    let mut flags = OpenFlags::empty();
    if types & SOCK_NONBLOCK != 0 {
        nonblock = true;
        types &= !SOCK_NONBLOCK;
        flags |= OpenFlags::O_NONBLOCK;
    } 
    if types & SOCK_CLOEXEC != 0 {
        types &= !SOCK_CLOEXEC;
        flags |= OpenFlags::O_CLOEXEC;
    }
    let types = SocketType::try_from(types as i32)?;
    let _protocol_inner = Protocol::try_from(protocol)?;
    protocol_check(protocol as u8, s_type)?;
    let socket = socket::Socket::new(domain,types, nonblock, protocol as u8);
    let fd_info = FdInfo {
        file: Arc::new(socket),
        flags: flags.into(),
    };
    let task = current_task().unwrap();
    let fd = task.with_mut_fd_table(|t|t.alloc_fd())?;
    task.with_mut_fd_table(|t| {
        t.put_file(fd, fd_info).or_else(|e|Err(e))
    })?;
    log::info!("[sys_socket]socket types:{:?}, fd: {}", types,fd);
    Ok(fd as isize)
}
/// “assigning a name to a socket”
pub fn sys_bind(fd: usize, addr: usize, addr_len: usize) -> SysResult {
    log::info!("[sys_bind] fd: {}, addr: {:#?}, addr_len: {}", fd, addr, addr_len);
    if (fd as isize) < 0 {
        return Err(SysError::EBADF);
    }
    if addr_len <= 3 {
        return Err(SysError::EINVAL);
    }
    let task = current_task().unwrap();
    let local_addr = sockaddr_reader(addr, addr_len, task)?;
    log::info!("[sys_bind] local_addr's port is: {}",unsafe {
        local_addr.ipv4
    });
    let socket_file = task.with_fd_table(|table| {
        table.get_file(fd)})?
        .downcast_arc::<socket::Socket>()
        .map_err(|_| SysError::ENOTSOCK)?;
    log::info!("[sys_bind] socket_file_type {:#?}, fd_type {:#?}", socket_file.sk_type, fd);

