#[repr(u32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Capability {
    /// 覆盖文件所有权限制 (POSIX)
    ///
    /// 在启用 `_POSIX_CHOWN_RESTRICTED` 的系统上，可修改文件所有者和组
    Chown = 0,

    /// 覆盖所有DAC访问限制 (POSIX)
    ///
    /// 包括ACL执行权限（若启用 `_POSIX_ACL`)，除 `LINUX_IMMUTABLE` 保护的文件
    DacOverride = 1,

    /// 覆盖文件/目录的读和搜索限制 (POSIX)
    ///
    /// 包括ACL限制（若启用 `_POSIX_ACL`)，除 `LINUX_IMMUTABLE` 保护的文件
    DacReadSearch = 2,

    /// 绕过文件操作UID匹配限制 (POSIX)
    ///
    /// 覆盖要求文件所有者UID必须等于用户UID的限制（`CAP_FSETID` 适用的情况除外）
    Fowner = 3,

    /// 绕过setuid/setgid位设置限制 (POSIX)
    ///
    /// 覆盖以下限制：
    /// - 设置 setuid 位时需有效用户ID匹配文件所有者
    /// - 设置 setgid 位时需有效组ID匹配文件所有者
    Fsetid = 4,

    /// 绕过信号发送权限检查 (POSIX)
    ///
    /// 覆盖发送信号时需真实/有效用户ID匹配接收进程的限制
    Kill = 5,

    /// 允许操纵组身份 (POSIX)
    ///
    /// 允许使用 setgid(2), setgroups(2)
    /// 允许在套接字凭证传递中伪造GID
    Setgid = 6,

    /// 允许操纵用户身份 (POSIX)
    ///
    /// 允许使用 setuid(2) 系列函数（包括fsuid）
    /// 允许在套接字凭证传递中伪造PID
    Setuid = 7,

    /// 能力边界集操作 (Linux扩展)
    ///
    /// 允许：
    /// - 向当前进程的可继承集添加能力
    /// - 从能力边界集移除能力
    /// - 修改进程的安全位（securebits）
    Setpcap = 8,

    /// 修改不可变/只追加文件属性 (Linux扩展)
    ///
    /// 允许修改 S_IMMUTABLE 和 S_APPEND 文件属性
    LinuxImmutable = 9,

    /// 绑定低端口网络服务 (Linux扩展)
    ///
    /// 允许绑定1024以下的TCP/UDP套接字
    /// 允许绑定32以下的ATM VCI
    NetBindService = 10,

    /// 网络广播和组播 (Linux扩展)
    ///
    /// 允许广播和监听组播
    NetBroadcast = 11,

    /// 网络管理权限 (Linux扩展)
    ///
    /// 允许：
    /// - 接口配置
    /// - IP防火墙/伪装/统计管理
    /// - 设置套接字调试选项
    /// - 修改路由表
